## 4. Real-World Example: Building a Resilient API Client

Let’s build a production-ready HTTP client that handles timeouts, retries, and structured errors.

```typescript
interface APIConfig {
  baseUrl: string;
  timeout?: number;
  maxRetries?: number;
}

class ApiClient {
  private config: Required<APIConfig>;

  constructor(config: APIConfig) {
    this.config = { timeout: 5000, maxRetries: 3, ...config };
  }

  async get<T>(endpoint: string): Promise<T> {
    let lastError: unknown;

    for (let attempt = 1; attempt <= this.config.maxRetries; attempt++) {
      try {
        const response = await fetchWithTimeout<T>(
          `${this.config.baseUrl}${endpoint}`,
          this.config.timeout
        );
        return response;
      } catch (error) {
        lastError = error;
        if (attempt < this.config.maxRetries) {
          await new Promise(res => setTimeout(res, 1000 * attempt));
          continue;
        }
        throw error;
      }
    }

    throw lastError!;
  }
}

// Usage
const client = new ApiClient({ baseUrl: 'https://api.example.com' });

async function loadUserData(userId: number): Promise<void> {
  try {
    const user = await client.get<User>(`/users/${userId}`);
    console.log('User:', user.name);
  } catch (error) {
    if (error instanceof APIError && error.statusCode === 404) {
      console.warn('User not found.');
    } else {
      console.error('Failed to load user:', error);
    }
  }
}
```

> 🔁 This client includes:
> - Automatic retries with backoff
> - Timeout handling
> - Custom error type discrimination
> - Clean, reusable structure

